Source.BuildSpec:
{
  "version": "0.2",
  "phases": {
    "install": {
      "commands": [
        "npm ci",
        "pip install uv"
      ]
    },
    "build": {
      "commands": [
        "npx cdk synth -c pipeline=true '**'",
        "uv run python scripts/check_validation_report.py cdk.out"
      ]
    }
  },
  "artifacts": {
    "base-directory": "cdk.out",
    "files": "**/*"
  }
}
